package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ObjectInputStream;
import java.io.ObjectStreamClass;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

class UnsafeAllocatorTest {

  @Test
  void testCreate_withSunMiscUnsafe() throws Exception {
    // Setup mocks for sun.misc.Unsafe path
    Class<?> unsafeClass = mock(Class.class);
    Field theUnsafeField = mock(Field.class);
    Object unsafeInstance = new Object();
    Method allocateInstanceMethod = mock(Method.class);

    // Mock Class.forName("sun.misc.Unsafe")
    try (var mockedStatic = mockStatic(Class.class)) {
      mockedStatic.when(() -> Class.forName("sun.misc.Unsafe")).thenReturn(unsafeClass);

      when(unsafeClass.getDeclaredField("theUnsafe")).thenReturn(theUnsafeField);
      doNothing().when(theUnsafeField).setAccessible(true);
      when(theUnsafeField.get(null)).thenReturn(unsafeInstance);
      when(unsafeClass.getMethod("allocateInstance", Class.class)).thenReturn(allocateInstanceMethod);

      UnsafeAllocator allocator = invokeCreate();

      // Create a dummy class to instantiate
      class Dummy {}

      // Prepare allocateInstance.invoke to return a Dummy instance
      when(allocateInstanceMethod.invoke(unsafeInstance, Dummy.class)).thenReturn(new Dummy());

      Dummy instance = allocator.newInstance(Dummy.class);
      assertNotNull(instance);
      assertEquals(Dummy.class, instance.getClass());
    }
  }

  @Test
  void testCreate_withObjectStreamClass() throws Exception {
    // Setup mocks for ObjectStreamClass path
    Method getConstructorIdMethod = mock(Method.class);
    Method newInstanceMethod = mock(Method.class);

    try (var mockedStaticClass = mockStatic(Class.class)) {
      mockedStaticClass.when(() -> Class.forName("sun.misc.Unsafe")).thenThrow(ClassNotFoundException.class);
      try (var mockedStaticOSC = mockStatic(ObjectStreamClass.class)) {
        // Mock getDeclaredMethod calls on ObjectStreamClass
        when(ObjectStreamClass.class.getDeclaredMethod("getConstructorId", Class.class)).thenReturn(getConstructorIdMethod);
        when(ObjectStreamClass.class.getDeclaredMethod("newInstance", Class.class, int.class)).thenReturn(newInstanceMethod);

        doNothing().when(getConstructorIdMethod).setAccessible(true);
        doNothing().when(newInstanceMethod).setAccessible(true);

        when(getConstructorIdMethod.invoke(null, Object.class)).thenReturn(123);
        UnsafeAllocator allocator = invokeCreate();

        class Dummy {}

        when(newInstanceMethod.invoke(null, Dummy.class, 123)).thenReturn(new Dummy());

        Dummy instance = allocator.newInstance(Dummy.class);
        assertNotNull(instance);
        assertEquals(Dummy.class, instance.getClass());
      }
    }
  }

  @Test
  void testCreate_withObjectInputStream() throws Exception {
    // Setup mocks for ObjectInputStream path
    Method newInstanceMethod = mock(Method.class);

    try (var mockedStaticClass = mockStatic(Class.class)) {
      mockedStaticClass.when(() -> Class.forName("sun.misc.Unsafe")).thenThrow(ClassNotFoundException.class);

      // Mock ObjectStreamClass methods to throw exceptions to skip to next block
      try (var mockedStaticOSC = mockStatic(ObjectStreamClass.class)) {
        when(ObjectStreamClass.class.getDeclaredMethod("getConstructorId", Class.class)).thenThrow(NoSuchMethodException.class);

        // Mock ObjectInputStream.getDeclaredMethod
        when(ObjectInputStream.class.getDeclaredMethod("newInstance", Class.class, Class.class)).thenReturn(newInstanceMethod);
        doNothing().when(newInstanceMethod).setAccessible(true);

        UnsafeAllocator allocator = invokeCreate();

        class Dummy {}

        when(newInstanceMethod.invoke(null, Dummy.class, Object.class)).thenReturn(new Dummy());

        Dummy instance = allocator.newInstance(Dummy.class);
        assertNotNull(instance);
        assertEquals(Dummy.class, instance.getClass());
      }
    }
  }

  @Test
  void testCreate_fallbackUnsupportedOperation() throws Exception {
    // Force all reflections to fail to get fallback allocator
    try (var mockedStaticClass = mockStatic(Class.class)) {
      mockedStaticClass.when(() -> Class.forName("sun.misc.Unsafe")).thenThrow(ClassNotFoundException.class);

      try (var mockedStaticOSC = mockStatic(ObjectStreamClass.class)) {
        when(ObjectStreamClass.class.getDeclaredMethod("getConstructorId", Class.class)).thenThrow(NoSuchMethodException.class);

        try (var mockedStaticOIS = mockStatic(ObjectInputStream.class)) {
          when(ObjectInputStream.class.getDeclaredMethod("newInstance", Class.class, Class.class)).thenThrow(NoSuchMethodException.class);

          UnsafeAllocator allocator = invokeCreate();

          class Dummy {}

          UnsupportedOperationException ex = assertThrows(UnsupportedOperationException.class, () -> allocator.newInstance(Dummy.class));
          assertTrue(ex.getMessage().contains("Cannot allocate"));
        }
      }
    }
  }

  // Utility method to invoke private static create() via reflection
  private UnsafeAllocator invokeCreate() throws Exception {
    Method createMethod = UnsafeAllocator.class.getDeclaredMethod("create");
    createMethod.setAccessible(true);
    return (UnsafeAllocator) createMethod.invoke(null);
  }
}
